python3 << 'EOF'
import subprocess
import json
from datetime import datetime, timedelta

models = {
    "us.anthropic.claude-sonnet-4-5-20250929-v1:0": {
        "name": "Sonnet 4.5",
        "input_price": 3.0,
        "output_price": 15.0,
        "cache_price": 0.3
    },
    "us.anthropic.claude-opus-4-6-v1": {
        "name": "Opus 4.6",
        "input_price": 15.0,
        "output_price": 75.0,
        "cache_price": 1.5
    },
    "us.anthropic.claude-haiku-4-5-20251001-v1:0": {
        "name": "Haiku 4.5",
        "input_price": 0.8,
        "output_price": 4.0,
        "cache_price": 0.08
    }
}

# 查询最近24小时
start_time = (datetime.utcnow() - timedelta(hours=24)).strftime('%Y-%m-%dT%H:%M:%S')
end_time = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%S')

print("=" * 100)
print("过去 24 小时每小时用量统计")
print("=" * 100)
print()

hourly_data = {}

for model_id, model_info in models.items():
    for metric in ['InputTokenCount', 'OutputTokenCount', 'CacheReadInputTokenCount']:
        cmd = [
            'aws', 'cloudwatch', 'get-metric-statistics',
            '--namespace', 'AWS/Bedrock',
            '--metric-name', metric,
            '--dimensions', f'Name=ModelId,Value={model_id}',
            '--start-time', start_time,
            '--end-time', end_time,
            '--period', '3600',
            '--statistics', 'Sum',
            '--output', 'json'
        ]

        result = subprocess.run(cmd, capture_output=True, text=True)
        if result.returncode == 0:
            data = json.loads(result.stdout)
            for point in data.get('Datapoints', []):
                timestamp = point['Timestamp'][:16].replace('T', ' ')
                if timestamp not in hourly_data:
                    hourly_data[timestamp] = {}
                if model_info['name'] not in hourly_data[timestamp]:
                    hourly_data[timestamp][model_info['name']] = {
                        'input': 0, 'output': 0, 'cache': 0,
                        'prices': model_info
                    }

                if metric == 'InputTokenCount':
                    hourly_data[timestamp][model_info['name']]['input'] = point['Sum']
                elif metric == 'OutputTokenCount':
                    hourly_data[timestamp][model_info['name']]['output'] = point['Sum']
                elif metric == 'CacheReadInputTokenCount':
                    hourly_data[timestamp][model_info['name']]['cache'] = point['Sum']

# 按时间排序并打印
for timestamp in sorted(hourly_data.keys()):
    print(f"\n⏰ {timestamp}")
    print("-" * 100)

    hour_total_cost = 0
    hour_total_tokens = 0

    for model_name in ['Sonnet 4.5', 'Opus 4.6', 'Haiku 4.5']:
        if model_name in hourly_data[timestamp]:
            data = hourly_data[timestamp][model_name]
            input_tokens = int(data['input'])
            output_tokens = int(data['output'])
            cache_tokens = int(data['cache'])

            if input_tokens + output_tokens + cache_tokens == 0:
                continue

            prices = data['prices']
            cost = (input_tokens / 1_000_000 * prices['input_price'] +
                   output_tokens / 1_000_000 * prices['output_price'] +
                   cache_tokens / 1_000_000 * prices['cache_price'])

            total_tokens = input_tokens + output_tokens + cache_tokens
            hour_total_cost += cost
            hour_total_tokens += total_tokens

            print(f"  {model_name:12s} | In: {input_tokens:>10,} | Out: {output_tokens:>10,} | Cache: {cache_tokens:>12,} | ${cost:>7.4f}")

    if hour_total_cost > 0:
        print(f"  {'总计':12s} | Tokens: {hour_total_tokens:>12,} | Cost: ${hour_total_cost:>7.4f}")

EOF

