            'aws', 'cloudwatch', 'get-metric-statistics',
            '--namespace', 'AWS/Bedrock',
            '--metric-name', metric,
            '--dimensions', f'Name=ModelId,Value={model_id}',
            '--start-time', start_time,
            '--end-time', end_time,
            '--period', '86400',  # 24小时
            '--statistics', 'Sum',
            '--output', 'json'
        ]

